mapper.select:
SELECT COUNT(*)
FROM TB_PM51M01 M
LEFT OUTER JOIN TB_PM52M01 RP ON M.TRIP_REQ_NO = RP.TRIP_REQ_NO
WHERE 1 = 1

	AND M.CO_CD = #{coCd}


	AND M.CREAT_DTTM BETWEEN TO_DATE(#{srchStDt}, 'YYYY-MM-DD') AND TO_DATE(#{srchEdDt}, 'YYYY-MM-DD') + 1


	AND M.TRIP_DIV = #{tripDiv}


	AND EXISTS (SELECT 1 FROM TB_PM51D01 D WHERE D.TRIP_REQ_NO = M.TRIP_REQ_NO AND D.USER_NM LIKE '%' || #{travelerNm} || '%')


	AND M.APRV_STS_CD = #{aprvStsCd}

SELECT M.TRIP_REQ_NO, M.TRIP_DIV, FN_CM05M01_CD_TO_NM(M.TRIP_DIV) AS TRIP_DIV_NM, M.TRIP_TYPE_CDS, FN_CM05M01_CD_TO_NM(M.TRIP_TYPE_CDS) AS TRIP_TYPE_CDS_NM, M.TRIP_PLACE, M.EQUIP_NM, SUBSTR(M.TRIP_ST_DTM, 1, 10) AS TRIP_ST_DTM, SUBSTR(M.TRIP_ED_DTM, 1, 10) AS TRIP_ED_DTM, M.NIGHT_CNT, M.DAY_CNT, M.SALES_CD, M.CLNT_CD, (SELECT CLNT_NM FROM TB_BM02M01 WHERE CLNT_CD = M.CLNT_CD) AS CLNT_NM, M.CLNT_PJT, FN_CM05M01_CD_TO_NM(M.CLNT_PJT) AS CLNT_PJT_NM, M.CURR_CD, FN_CM05M01_CD_TO_NM(M.CURR_CD) AS CURR_CD_NM, M.APRV_STS_CD, FN_CM05M01_CD_TO_NM(M.APRV_STS_CD) AS APRV_STS_NM, CASE WHEN LENGTH(M.PAY_DT) = 8 THEN SUBSTR(M.PAY_DT, 1, 4) || '-' || SUBSTR(M.PAY_DT, 5, 2) || '-' || SUBSTR(M.PAY_DT, 7, 2) ELSE M.PAY_DT END AS PAY_DT, M.PAY_ID, FN_CM06M01_ID_TO_NM(M.PAY_ID) AS PAY_NM, M.CREAT_ID, M.CREAT_DTTM, RP.TRIP_RPT_NO AS TRIP_RPT_NO, CASE WHEN RP.TRIP_RPT_NO IS NULL THEN 'N' ELSE 'Y' END AS TRIP_RPT_YN, (SELECT COUNT(*) FROM TB_WB20M03 WHERE TODO_NO = M.TRIP_REQ_NO AND TODO_DIV2_CODE_ID = 'TODODIV2190') AS APP_TOT_CNT, (SELECT COUNT(*) FROM TB_WB20M03 WHERE TODO_NO = M.TRIP_REQ_NO AND TODO_DIV2_CODE_ID = 'TODODIV2190' AND SANCTN_STTUS = 'Y') AS APP_DONE_CNT, (SELECT COUNT(*) FROM TB_WB20M03 WHERE TODO_NO = M.TRIP_REQ_NO AND TODO_DIV2_CODE_ID = 'TODODIV2191') AS PAY_APP_TOT_CNT, (SELECT COUNT(*) FROM TB_WB20M03 WHERE TODO_NO = M.TRIP_REQ_NO AND TODO_DIV2_CODE_ID = 'TODODIV2191' AND SANCTN_STTUS = 'Y') AS PAY_APP_DONE_CNT, (SELECT LISTAGG(D.USER_NM, ', ') WITHIN GROUP (ORDER BY D.SEQ) FROM TB_PM51D01 D WHERE D.TRIP_REQ_NO = M.TRIP_REQ_NO) AS TRAVELER_LIST, (SELECT SUBSTR(MIN(D.TRIP_ST_DTM), 1, 10) || '~' || SUBSTR(MAX(D.TRIP_ED_DTM), 1, 10) FROM TB_PM51D01 D WHERE D.TRIP_REQ_NO = M.TRIP_REQ_NO) AS TRIP_PERIOD FROM TB_PM51M01 M LEFT OUTER JOIN TB_PM52M01 RP ON M.TRIP_REQ_NO = RP.TRIP_REQ_NO WHERE 1 = 1
AND M.CO_CD = #{coCd}
AND M.CREAT_DTTM BETWEEN TO_DATE(#{srchStDt}, 'YYYY-MM-DD') AND TO_DATE(#{srchEdDt}, 'YYYY-MM-DD') + 1
AND M.TRIP_DIV = #{tripDiv}
AND EXISTS (SELECT 1 FROM TB_PM51D01 D WHERE D.TRIP_REQ_NO = M.TRIP_REQ_NO AND D.USER_NM LIKE '%' || #{travelerNm} || '%')
AND M.APRV_STS_CD = #{aprvStsCd}
AND M.SALES_CD LIKE '%' || #{salesCd} || '%'
ORDER BY M.CREAT_DTTM DESC

mapper.insert:
INSERT INTO TB_PM51D01 (
	TRIP_REQ_NO, SEQ, USER_ID, DEPT_NM, POSITION_NM, USER_NM,
	TRIP_ST_DTM, TRIP_ED_DTM, NIGHT_CNT, DAY_CNT, EAT_CNT,
	TRAFFIC_AMT, LODGING_AMT, MEAL_AMT, DAILY_AMT, SPECIAL_AMT, TOTAL_AMT, ETC
) VALUES (
	#{tripReqNo}, NVL((SELECT MAX(SEQ) FROM TB_PM51D01 WHERE TRIP_REQ_NO = #{tripReqNo}), 0) + 1,
	#{userId, jdbcType=VARCHAR}, #{deptNm, jdbcType=VARCHAR}, #{positionNm, jdbcType=VARCHAR}, #{userNm, jdbcType=VARCHAR},
	#{tripStDtm, jdbcType=VARCHAR}, #{tripEdDtm, jdbcType=VARCHAR}, #{nightCnt, jdbcType=NUMERIC}, #{dayCnt, jdbcType=NUMERIC}, #{eatCnt, jdbcType=NUMERIC},
	#{trafficAmt, jdbcType=NUMERIC}, #{lodgingAmt, jdbcType=NUMERIC}, #{mealAmt, jdbcType=NUMERIC}, #{dailyAmt, jdbcType=NUMERIC}, #{specialAmt, jdbcType=NUMERIC}, #{totalAmt, jdbcType=NUMERIC}, #{etc, jdbcType=VARCHAR}
)

INSERT INTO TB_PM51D02 (
	TRIP_REQ_NO, SEQ, EXP_ITEM_CD, CURR_CD, KRW_AMT, USD_AMT, CALC_BASIS, REMARK
) VALUES (
	#{tripReqNo}, NVL((SELECT MAX(SEQ) FROM TB_PM51D02 WHERE TRIP_REQ_NO = #{tripReqNo}), 0) + 1,
	#{expItemCd, jdbcType=VARCHAR}, #{currCd, jdbcType=VARCHAR}, #{krwAmt, jdbcType=NUMERIC}, #{usdAmt, jdbcType=NUMERIC}, #{calcBasis, jdbcType=VARCHAR}, #{remark, jdbcType=VARCHAR}
)

mapper.delete:
DELETE FROM TB_WB20M03
WHERE TODO_NO = #{reqNo}
	AND TODO_DIV2_CODE_ID IN ('TODODIV1190', 'TODODIV2190', 'TODODIV1191', 'TODODIV2191', 'TODODIV1200', 'TODODIV2200', 'TODODIV1201', 'TODODIV2201')

mapper.select:
SELECT COUNT(*) FROM TB_PM52M01 M WHERE 1 = 1
AND M.CO_CD = #{coCd}
AND M.CREAT_DTTM BETWEEN TO_DATE(#{srchStDt}, 'YYYY-MM-DD') AND TO_DATE(#{srchEdDt}, 'YYYY-MM-DD') + 1
AND EXISTS (SELECT 1 FROM TB_PM51M01 R WHERE R.TRIP_REQ_NO = M.TRIP_REQ_NO AND R.TRIP_DIV = #{tripDiv})
AND M.APRV_STS_CD = #{aprvStsCd}

SELECT M.TRIP_RPT_NO, M.TRIP_REQ_NO, M.ACT_ST_DTM, M.ACT_ED_DTM, SUBSTR(M.ACT_ST_DTM, 1, 10) || '~' || SUBSTR(M.ACT_ED_DTM, 1, 10) AS ACT_PERIOD, M.SETTLE_AMT_KRW, M.SETTLE_AMT_USD, M.FINAL_EVAL_CD, FN_CM05M01_CD_TO_NM(M.FINAL_EVAL_CD) AS FINAL_EVAL_NM, M.APRV_STS_CD, FN_CM05M01_CD_TO_NM(M.APRV_STS_CD) AS APRV_STS_NM, M.CREAT_ID, M.CREAT_DTTM, R.TRIP_DIV, FN_CM05M01_CD_TO_NM(R.TRIP_DIV) AS TRIP_DIV_NM, R.TRIP_TYPE_CDS, FN_CM05M01_CD_TO_NM(R.TRIP_TYPE_CDS) AS TRIP_TYPE_CDS_NM, R.TRIP_PLACE, R.EQUIP_NM, R.SALES_CD, R.CLNT_CD, (SELECT CLNT_NM FROM TB_BM02M01 WHERE CLNT_CD = R.CLNT_CD) AS CLNT_NM, R.CLNT_PJT, FN_CM05M01_CD_TO_NM(R.CLNT_PJT) AS CLNT_PJT_NM, R.CURR_CD, FN_CM05M01_CD_TO_NM(R.CURR_CD) AS CURR_CD_NM, (SELECT COUNT(*) FROM TB_WB20M03 WHERE TODO_NO = M.TRIP_RPT_NO AND TODO_DIV2_CODE_ID = 'TODODIV2200') AS APP_TOT_CNT, (SELECT COUNT(*) FROM TB_WB20M03 WHERE TODO_NO = M.TRIP_RPT_NO AND TODO_DIV2_CODE_ID = 'TODODIV2200' AND SANCTN_STTUS = 'Y') AS APP_DONE_CNT, (SELECT LISTAGG(D.USER_NM, ', ') WITHIN GROUP (ORDER BY D.SEQ) FROM TB_PM52D02 D WHERE D.TRIP_RPT_NO = M.TRIP_RPT_NO) AS TRAVELER_LIST FROM TB_PM52M01 M INNER JOIN TB_PM51M01 R ON M.TRIP_REQ_NO = R.TRIP_REQ_NO WHERE 1 = 1
AND M.CO_CD = #{coCd}
AND M.CREAT_DTTM BETWEEN TO_DATE(#{srchStDt}, 'YYYY-MM-DD') AND TO_DATE(#{srchEdDt}, 'YYYY-MM-DD') + 1
AND R.TRIP_DIV = #{tripDiv}
AND M.APRV_STS_CD = #{aprvStsCd}
AND M.TRIP_REQ_NO = #{tripReqNo}
AND R.SALES_CD LIKE '%' || #{salesCd} || '%'
AND EXISTS ( SELECT 1 FROM TB_PM52D02 D WHERE D.TRIP_RPT_NO = M.TRIP_RPT_NO AND D.USER_NM LIKE '%' || #{travelerNm} || '%' )
ORDER BY M.CREAT_DTTM DESC

SELECT M.TRIP_REQ_NO, M.TRIP_DIV, M.TRIP_PLACE, M.EQUIP_NM, M.TRIP_ST_DTM, M.TRIP_ED_DTM, M.NIGHT_CNT, M.DAY_CNT FROM TB_PM51M01 M WHERE M.APRV_STS_CD = 'APRVSTS03' AND NOT EXISTS (SELECT 1 FROM TB_PM52M01 RP WHERE RP.TRIP_REQ_NO = M.TRIP_REQ_NO)
AND M.CO_CD = #{coCd}
ORDER BY M.CREAT_DTTM DESC

